import{_ as i,o as n,c as a,a4 as t,j as o}from"./chunks/framework.Cqne-ChA.js";const r="/assets/ZopenCommunity-Contributor-Color.EKsvUPDD.png",s="/assets/ZopenCommunity-SignificantContributor-Color.FYHV544Z.png",f=JSON.parse('{"title":"zopen community Badges","description":"","frontmatter":{},"headers":[],"relativePath":"Badges.md","filePath":"Badges.md","lastUpdated":1776684549000}'),l={name:"Badges.md"};function d(c,e,m,u,p,b){return n(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="zopen-community-badges" tabindex="-1">zopen community Badges <a class="header-anchor" href="#zopen-community-badges" aria-label="Permalink to &quot;zopen community Badges&quot;">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>Welcome to the zopen community badge program! These badges are designed to recognize and celebrate the valuable contributions of our members. Whether you are submitting code, improving documentation, or porting essential tools, your efforts help our community grow and thrive. This program, powered by Credly, formally acknowledges that work and showcases the impactful achievements of individuals within our ecosystem.</p><h2 id="how-to-submit-a-nomination" tabindex="-1">How to Submit a Nomination <a class="header-anchor" href="#how-to-submit-a-nomination" aria-label="Permalink to &quot;How to Submit a Nomination&quot;">​</a></h2><p>Badges are awarded based on evidence of contribution. We encourage both self-nominations and nominations for other deserving community members whose work you admire.</p><p>To submit a nomination, please complete our online nomination form:</p>',6),o("p",null,[o("a",{href:"https://docs.google.com/forms/d/e/1FAIpQLSdsq902oSpRJPfxZrvE_b3EVKUzY0VMbYPd6CBvrUGSBNgOtQ/viewform?usp=sf_link",target:"_blank",style:{display:"inline-block",padding:"10px 20px","font-size":"16px","font-weight":"bold",color:"#ffffff","background-color":"#007bff","text-align":"center","text-decoration":"none","border-radius":"5px",transition:"background-color 0.2s"},onmouseover:"this.style.backgroundColor='#0056b3'",onmouseout:"this.style.backgroundColor='#007bff'"}," ✍️ Submit a Nomination ")],-1),t('<p>You will be asked to provide the following information:</p><ul><li>The nominee&#39;s full name and email address.</li><li>The specific badge you are nominating them for.</li><li>A clear description of the contributions</li><li>Links to evidence (e.g., pull requests, commits, project repositories, or other public resources).</li></ul><p>Nominations are reviewed on by the <strong><a href="./team">zopen Technical Steering Committee (TSC)</a></strong>. Badges can be awarded retroactively for past contributions.</p><h3 id="review-timeline" tabindex="-1">Review Timeline <a class="header-anchor" href="#review-timeline" aria-label="Permalink to &quot;Review Timeline&quot;">​</a></h3><p>Once a nomination form is submitted, please allow <strong>up to 1 month</strong> for the review. Nominees will receive a response or be awarded their badge within <strong>1-2 months</strong> after the submission date.</p><h1 id="🛡️-list-of-badges" tabindex="-1">🛡️ List of Badges <a class="header-anchor" href="#🛡️-list-of-badges" aria-label="Permalink to &quot;🛡️ List of Badges&quot;">​</a></h1><table style="width:100%;display:table;"><tr><td align="center" style="width:auto;max-width:280px;"><img src="'+r+'" alt="zopen community contributor" style="width:100% !important;margin:0;padding:5px;display:block;"></td><td><strong>zopen community contributor: Awarded for making a substantive, accepted contribution to the zopen community.</strong><br><br> This includes successfully porting a new project, or submitting a substantial pull request that implements a significant feature or resolves a critical bug. </td></tr></table><h3 id="examples-of-contributions" tabindex="-1">Examples of Contributions <a class="header-anchor" href="#examples-of-contributions" aria-label="Permalink to &quot;Examples of Contributions&quot;">​</a></h3><ul><li>Successfully porting a project to z/OS and contributing it to the zopen community.</li><li>Submitting a substantial pull request that improves z/OS functionality for an existing tool. For example, a pull request that implements a significant new feature or resolves a critical performance bug (e.g., <a href="https://github.com/zopencommunity/meta/pull/1061" target="_blank" rel="noreferrer">Enable ccache support for clang builds to speed up recompilation #1061 </a>)</li></ul>',9),o("p",null,[o("a",{href:"https://docs.google.com/forms/d/e/1FAIpQLSdsq902oSpRJPfxZrvE_b3EVKUzY0VMbYPd6CBvrUGSBNgOtQ/viewform?usp=sf_link",target:"_blank",style:{display:"inline-block",padding:"10px 20px","font-size":"16px","font-weight":"bold",color:"#ffffff","background-color":"#007bff","text-align":"center","text-decoration":"none","border-radius":"5px",transition:"background-color 0.2s"},onmouseover:"this.style.backgroundColor='#0056b3'",onmouseout:"this.style.backgroundColor='#007bff'"}," ✍️ Submit a Nomination ")],-1),t('<hr><table style="width:100%;display:table;"><tr><td align="center" style="width:auto;max-width:280px;"><img src="'+s+'" alt="zopen community contributor" style="width:100% !important;margin:0;padding:5px;display:block;"></td><td><strong>zopen community significant contributor: Awarded to individuals who demonstrate sustained and impactful contributions over time.</strong><br><br> This includes maintaining critical packages, making a high volume of quality contributions, or introducing foundational improvements to the community. </td></tr></table><h3 id="examples-of-contributions-1" tabindex="-1">Examples of Contributions <a class="header-anchor" href="#examples-of-contributions-1" aria-label="Permalink to &quot;Examples of Contributions&quot;">​</a></h3><ul><li>Submitted <strong>10 or more accepted pull requests</strong> across any zopen community repositories.</li><li>Ported or maintained a <strong>complex or foundational tool</strong>.</li><li>Introduced <strong>improvements</strong> such as automation, tooling, or design patterns used across multiple packages.</li><li>Maintained packages that serve as <strong>critical dependencies</strong> in the ecosystem over time.</li></ul>',4),o("p",null,[o("a",{href:"https://docs.google.com/forms/d/e/1FAIpQLSdsq902oSpRJPfxZrvE_b3EVKUzY0VMbYPd6CBvrUGSBNgOtQ/viewform?usp=sf_link",target:"_blank",style:{display:"inline-block",padding:"10px 20px","font-size":"16px","font-weight":"bold",color:"#ffffff","background-color":"#007bff","text-align":"center","text-decoration":"none","border-radius":"5px",transition:"background-color 0.2s"},onmouseover:"this.style.backgroundColor='#0056b3'",onmouseout:"this.style.backgroundColor='#007bff'"}," ✍️ Submit a Nomination ")],-1)])])}const h=i(l,[["render",d]]);export{f as __pageData,h as default};
